// Entrada vía Webhook HTTP (disparado por Etapa A o por Apps Script onEdit)
const j = $input.first().json.body || $input.first().json;
if (!j.caso_id) {
  throw new Error('El webhook de Etapa B llegó sin caso_id en el body. Se esperaba { "caso_id": "..." }.');
}
return [{ json: { caso_id: String(j.caso_id), modo: j.modo || 'oficiamiento' } }];

// Entrada vía Execute Workflow (reutilizado desde Etapa D para diligenciamiento)
const j = $input.first().json;
if (!j.caso_id) {
  throw new Error('Etapa D llamó a Etapa B sin caso_id.');
}
return [{ json: { caso_id: String(j.caso_id), modo: j.modo || 'diligenciamiento' } }];

// A partir de los campos del caso, arma un item por cada institución a oficiar.
// v3.2: soporta ambos triggers sin romper (isExecuted), falla claro si el caso no existe
// y si no se identifica ninguna institución deriva el caso al centro médico del estudio (fallback).
let entrada = { caso_id: '(desconocido)', modo: 'oficiamiento' };
try { if ($('Normalizar entrada (Webhook)').isExecuted) entrada = $('Normalizar entrada (Webhook)').first().json; } catch (e) { /* no ejecutado */ }
try { if ($('Normalizar entrada (Execute Workflow)').isExecuted) entrada = $('Normalizar entrada (Execute Workflow)').first().json; } catch (e) { /* no ejecutado */ }
const modo = entrada.modo || 'oficiamiento';

const items = $input.all();
if (items.length === 0 || !items[0].json.caso_id) {
  throw new Error(`Caso ${entrada.caso_id}: no se encontró en la hoja Casos. Verificar el caso_id antes de oficiar.`);
}
const caso = items[0].json;

const instituciones = [];

if (caso.dependencia_policial) {
  instituciones.push({
    tipo_institucion: 'comisaria_ministerio_seguridad',
    institucion: caso.dependencia_policial,
    objeto: `Remisión de actuaciones / sumario N° ${caso.numero_sumario || 's/n'} referido al hecho del ${caso.fecha_hora_hecho}`,
  });
}
if (caso.aseguradora_propia) {
  instituciones.push({
    tipo_institucion: 'aseguradora',
    institucion: caso.aseguradora_propia,
    objeto: 'Informe de póliza y cobertura vigente a la fecha del hecho',
  });
}
if (caso.aseguradora_tercero) {
  instituciones.push({
    tipo_institucion: 'aseguradora',
    institucion: caso.aseguradora_tercero,
    objeto: 'Informe de póliza y cobertura del vehículo tercero interviniente',
  });
}

let asistencia = {};
try { asistencia = JSON.parse(caso.asistencia_medica_json || '{}'); } catch (e) { /* queda vacío */ }
if (asistencia.hospital) {
  instituciones.push({
    tipo_institucion: 'hospital',
    institucion: asistencia.hospital,
    objeto: 'Historia clínica y parte de atención del hecho',
  });
}
if (asistencia.same) {
  instituciones.push({
    tipo_institucion: 'same',
    institucion: 'SAME',
    objeto: 'Parte de asistencia prehospitalaria',
  });
}

// --- Fallback: sin instituciones externas identificables, el caso lo revisa el centro médico del estudio ---
if (instituciones.length === 0) {
  const huboLesiones = String(caso.hubo_lesiones).toLowerCase() === 'true';
  const detalleLesiones = huboLesiones
    ? `Lesiones informadas por el cliente${caso.detalle_lesiones ? ': ' + caso.detalle_lesiones : ''}.`
    : 'Sin lesiones informadas en la captación.';
  instituciones.push({
    tipo_institucion: 'centro_medico_estudio',
    institucion: 'Centro Médico del Estudio Jurídico',
    objeto: `Revisión médica inicial del cliente ${caso.nombre_apellido_cliente || 's/d'} `
      + `(caso sin instituciones externas a oficiar). ${detalleLesiones} `
      + `Hecho del ${caso.fecha_hora_hecho || 's/d'} en ${caso.lugar_hecho || 's/d'}.`,
  });
}

return instituciones.map(inst => ({ json: { ...caso, ...inst, modo } }));

// Autocompleta plantilla según tipo de institución (sin IA - section 4.1) y arma nombre de archivo.
// v3.1: corre por item (varias instituciones = varios oficios) y solo elige email si HAY destinatario.
const item = $json;

// En ejecuciones parciales (Execute step) el nodo 'Leer tabla de plantillas' puede no haber corrido
// porque es una rama paralela: en ese caso se usa catálogo vacío y el oficio cae a canal presencial.
// En la ejecución completa del workflow las plantillas siempre están disponibles.
let plantillas = [];
try { plantillas = $('Leer tabla de plantillas').all().map(x => x.json); } catch (e) { plantillas = []; }
const match = plantillas.find(p => p.tipo_institucion === item.tipo_institucion) || {};

const plantillaAceptaEmail = [true, 'TRUE', 'true', 1, '1'].includes(match.acepta_email);
const emailDestino = String(match.email_destino_default || item.email_destino || '').trim();
const aceptaEmail = plantillaAceptaEmail && emailDestino !== '';

const hoy = new Date().toISOString().slice(0, 10);
const seq = String(Math.floor(Math.random() * 900) + 100);
const institucionUpper = String(item.institucion || match.nombre_plantilla || item.tipo_institucion).toUpperCase();

const nombre_archivo = item.modo === 'diligenciamiento'
  ? `DILIGENCIAMIENTO-OFICIO JUDICIAL A ${institucionUpper}_${seq}`
  : `OFICIO COLEGIACION ${institucionUpper} - NORMAL ${seq}`;

const oficio_id = `${item.caso_id}_${item.tipo_institucion}_${seq}`;

const texto_oficio = `Por la presente, en el marco del caso ${item.caso_id}, se solicita a ${item.institucion} `
  + `lo siguiente: ${item.objeto}. Hecho de fecha ${item.fecha_hora_hecho} ocurrido en ${item.lugar_hecho}.`;

return {
  json: {
    ...item,
    oficio_id,
    nombre_archivo,
    texto_oficio,
    acepta_email: aceptaEmail,
    email_destino: emailDestino,
    fecha_envio_original: hoy,
    fecha_ultimo_envio: hoy,
  }
};

// Estados de timer: Enviado -> Reiterado 1 -> Reiterado 2 -> Vencido sin respuesta.
// Una clasificación de respuesta (4.3) puede sacar al oficio de este ciclo en cualquier momento.
const HOY = Date.now();
const salida = [];
for (const item of $input.all()) {
  const j = item.json;
  if (!['Enviado', 'Reiterado 1', 'Reiterado 2'].includes(j.estado)) continue;
  const t = new Date(j.fecha_ultimo_envio).getTime();
  if (isNaN(t)) continue;  // fecha inválida o vacía: no rompe el cron, se ignora la fila
  const dias = (HOY - t) / (1000 * 60 * 60 * 24);
  if (dias < 5) continue;

  if (j.estado === 'Reiterado 2') {
    salida.push({ json: { ...j, accion: 'vencer' } });
  } else {
    const numero_reiteracion = j.estado === 'Enviado' ? 1 : 2;
    salida.push({ json: { ...j, accion: 'reiterar', numero_reiteracion } });
  }
}
return salida;

// Prompt 4.2 del documento maestro, con variables ya resueltas (evita colisión de sintaxis {{ }} con n8n)
const j = $json;
const prompt_final = `Redactá una nota de reiteración formal para un oficio judicial/administrativo
que no obtuvo respuesta en el plazo esperado. Usá el registro de lenguaje
propio de la práctica judicial argentina, tono respetuoso pero firme,
sin amenazas explícitas, dejando constancia de la falta de respuesta y del
plazo transcurrido.

Datos del oficio original:
- Institución destinataria: ${j.institucion}
- N° de oficio / referencia: ${j.oficio_id}
- Fecha de envío original: ${j.fecha_envio_original}
- N° de reiteración (1 o 2): ${j.numero_reiteracion}
- Objeto del oficio: ${j.objeto}

Instrucciones de tono según número de reiteración:
- Reiteración 1: formal, recordatorio simple del plazo vencido.
- Reiteración 2: formal, más firme, mencionando que se trata de la segunda
  solicitud y que la falta de respuesta reiterada puede requerir escalarse
  por otras vías.

Devolvé solo el texto de la nota, listo para insertar en la plantilla
membretada del estudio. No agregues explicaciones fuera del texto.`;

return { json: { ...j, prompt_final } };

// El chainLlm solo devuelve {text}: se recupera el oficio original desde el nodo del prompt.
const j = $('Armar prompt de reiteración').item.json;
const texto_ia = $json.text || $json.output || '';

const seq = String(Math.floor(Math.random() * 900) + 100);
const institucionUpper = String(j.institucion).toUpperCase();
const tag = j.numero_reiteracion === 1 ? 'REITERACION DEBIL' : 'REITERACION FUERTE';

const nombre_archivo = j.modo === 'diligenciamiento'
  ? `DILIGENCIAMIENTO-OFICIO JUDICIAL A ${institucionUpper} - REITERACION ${j.numero_reiteracion}_${seq}`
  : `OFICIO COLEGIACION ${institucionUpper} - ${tag} ${seq}`;

const nuevo_estado = `Reiterado ${j.numero_reiteracion}`;

return { json: { ...j, texto_ia, nombre_archivo, nuevo_estado } };

// Normaliza el email entrante (Gmail Trigger, salida simplificada) para el prompt de clasificacion.
// v3.1: corre por item, por si el poll trae varios emails a la vez.
const m = $json;
const de = m.from?.value?.[0]?.address || m.From || (typeof m.from === 'string' ? m.from : '') || '';
const asunto = m.subject || m.Subject || '';
const cuerpo = m.text || m.textPlain || m.snippet || '';
const contenido_email = `De: ${de}\nAsunto: ${asunto}\n\n${cuerpo}`;
return { json: { contenido_email, email_from: de, email_subject: asunto } };

// v3.2: mapea estados a la convención de la hoja, extrae oficio_id y decide la ruta de cada email.
// Nunca descarta items en silencio: los no relacionados salen con ruta='descartado' (visible en el canvas).
const MAPA_ESTADOS = {
  respondida: 'Respondida',
  respondida_parcial: 'Respondida parcial',
  rechazo_solicitud: 'Rechazo solicitud',
};

const salida = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const texto = items[i].json.text || items[i].json.output || '';
  let parsed = null;
  try {
    const match = texto.match(/\{[\s\S]*\}/);
    parsed = match ? JSON.parse(match[0]) : null;
  } catch (e) { /* parsed queda null */ }

  let mail = {};
  try { mail = $('Normalizar email entrante').itemMatching(i).json; }
  catch (e) { mail = $('Normalizar email entrante').first().json; }

  const estadoRaw = parsed?.estado ?? null;
  const estado_respuesta = MAPA_ESTADOS[estadoRaw] || null;

  // ruta: 'vinculado' actualiza el oficio; 'sin_vincular' alerta para revisión humana;
  // 'descartado' = publicidad/no relacionado, termina visible sin alertar.
  let ruta;
  if (estadoRaw === 'no_corresponde_a_oficio') ruta = 'descartado';
  else if (estado_respuesta && parsed?.caso_id) ruta = 'vinculado';
  else ruta = 'sin_vincular';

  salida.push({
    json: {
      ruta,
      caso_id: ruta === 'vinculado' ? parsed.caso_id : null,
      oficio_id: parsed?.oficio_id ?? null,
      estado_respuesta,
      resumen: parsed?.resumen ?? 'No se pudo interpretar la clasificación generada por el LLM.',
      email_from: mail.email_from,
      email_subject: mail.email_subject,
      contenido_email: mail.contenido_email,
    },
    pairedItem: { item: i },
  });
}
return salida;

// Convención real: '<APELLIDO NOMBRE> DYP- OFICIO JUDICIAL- FIRMADO <REMITENTE>_<seq>'
// v3.3: tolera ejecuciones parciales (Execute step) y entradas vacías; loguea a consola para debug.

// 1) Fila del caso leída de la hoja Casos (puede venir vacía si el caso_id del LLM no existe)
const caso = ($input.all()[0] && $input.all()[0].json) || {};

// 2) Clasificación del email (si 'Parsear clasificación' no corrió en un Execute step, objeto vacío)
let p = {};
try { p = $('Parsear clasificación').first().json; } catch (e) { p = {}; }

const seq = String(Math.floor(Math.random() * 900) + 100);
const cliente = String(caso.nombre_apellido_cliente || 'CLIENTE').toUpperCase().trim();
const remitente = String(p.email_from || 'INSTITUCION').toUpperCase().replace(/[\\/:*?"<>|]/g, '').trim();

const nombre_archivo = `${cliente} DYP- OFICIO JUDICIAL- FIRMADO ${remitente}_${seq}`;

console.log('[Nombre de archivo de respuesta] caso_id:', p.caso_id ?? caso.caso_id ?? '(sin caso)');
console.log('[Nombre de archivo de respuesta] carpeta_drive_id:', caso.carpeta_drive_id || '(sin carpeta, va a raíz de Drive)');
console.log('[Nombre de archivo de respuesta] nombre_archivo:', nombre_archivo);

return [{
  json: {
    ...p,
    caso_id: p.caso_id || caso.caso_id || null,
    nombre_archivo,
    carpeta_drive_id: caso.carpeta_drive_id || null,
  }
}];
